import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

interface User {
  userId: number;
  username: string;
  email: string;
  firstname?: string;
  lastname?: string;
  role: string;
}

const Dashboard: React.FC = () => {
  const navigate = useNavigate();
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    // Check if user is logged in
    const token = localStorage.getItem('token');
    const userStr = localStorage.getItem('user');

    if (!token || !userStr) {
      navigate('/login');
      return;
    }

    setUser(JSON.parse(userStr));
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  if (!user) return null;

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background-light to-primary-dark">
      {/* Header */}
      <header className="bg-primary shadow-lg">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <span className="text-4xl">🎬</span>
              <h1 className="text-2xl font-bold text-white">
                [<span className="text-red-500">●</span>StreamStack<span className="text-yellow-500">📚</span>]
              </h1>
            </div>
            <button
              onClick={handleLogout}
              className="bg-white text-primary hover:bg-gray-100 px-4 py-2 rounded-lg font-semibold transition"
            >
              Logout
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        {/* Welcome Card */}
        <div className="bg-white rounded-2xl shadow-2xl p-8 mb-8">
          <h2 className="text-3xl font-bold text-gray-800 mb-4">
            Welcome back, {user.firstname || user.username}! 👋
          </h2>
          <p className="text-gray-600 text-lg">
            You're successfully logged in to StreamStack.
          </p>
        </div>

        {/* User Info Card */}
        <div className="bg-white rounded-2xl shadow-2xl p-8">
          <h3 className="text-2xl font-bold text-gray-800 mb-6">Profile Information</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-gray-600 mb-2">Username</label>
              <p className="text-lg text-gray-800">{user.username}</p>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-600 mb-2">Email</label>
              <p className="text-lg text-gray-800">{user.email}</p>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-600 mb-2">First Name</label>
              <p className="text-lg text-gray-800">{user.firstname || 'Not provided'}</p>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-600 mb-2">Last Name</label>
              <p className="text-lg text-gray-800">{user.lastname || 'Not provided'}</p>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-600 mb-2">Role</label>
              <p className="text-lg text-gray-800">{user.role}</p>
            </div>
          </div>
        </div>

        {/* Features Coming Soon */}
        <div className="bg-primary rounded-2xl shadow-2xl p-8 mt-8 text-center">
          <h3 className="text-2xl font-bold text-white mb-4">More Features Coming Soon!</h3>
          <p className="text-blue-100 text-lg">
            Movie browsing, watchlists, and history tracking will be available in the next phase.
          </p>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
